#!/usr/bin/env python3
from __future__ import annotations

import argparse
import json
import subprocess
import sys
import tempfile
from datetime import datetime, timezone
from pathlib import Path
from typing import Any

DEFAULT_INPUT_DIR = "~/Desktop/pdf样本"
DEFAULT_OUTPUT_XLSX = "artifacts/outputs/trello_readonly/pdf_to_excel_from_trello.xlsx"
DEFAULT_OCR = "auto"
DEFAULT_DRY_RUN = False
DEFAULT_ORIGIN_ID = "trello:69c24cd3c1a2359ddd7a1bf8"
DEFAULT_TITLE = "BL-20260324-014 live preview smoke sample 2026-03-24 (best-effort reviewable attempt)"
DEFAULT_DESCRIPTION = (
    "Purpose: | Controlled Trello live preview smoke for openclaw-team. | "
    "Expected behavior: | - read-only Trello ingest | - preview creation smoke only | "
    "Traceability: | - backlog: BL-20260324-014"
)
DEFAULT_LABELS = ["best_effort", "evidence_backed", "readonly", "reviewable", "trello"]
DEFAULT_PREFERRED_BASE_SCRIPT = "artifacts/scripts/pdf_to_excel_ocr.py"
DEFAULT_DELEGATE_TIMEOUT_SECONDS = 120
DEFAULT_REFERENCE_DOCS = [
    "artifacts/docs/pdf_to_excel_ocr_usage.md",
    "artifacts/reviews/pdf_to_excel_ocr_review.md",
]
RUNNER_PATH = Path(__file__).resolve()
REPO_ROOT = RUNNER_PATH.parents[2]
APPROVED_OUTPUT_ROOT = (REPO_ROOT / "artifacts" / "outputs").resolve()
REVIEWED_BASE_SCRIPT = (REPO_ROOT / DEFAULT_PREFERRED_BASE_SCRIPT).resolve()
ALLOWED_SUMMARY_STATUSES = {"success", "partial", "failed"}
ALLOWED_EXTRACTION_STATUSES = {"none", "success", "partial", "failed"}
ALLOWED_EXPORT_STATUSES = {
    "not_started",
    "running",
    "succeeded",
    "failed",
    "skipped_dry_run",
    "skipped_no_input",
    "unknown",
}
DIAGNOSTIC_EXCERPT_LIMIT = 1200


def utc_now() -> str:
    return datetime.now(timezone.utc).isoformat()


def expand_path(path_str: str) -> Path:
    return Path(path_str).expanduser()


def repo_relative_path(path: Path) -> str | None:
    try:
        return str(path.relative_to(REPO_ROOT))
    except ValueError:
        return None


def resolve_delegate_script(path_str: str) -> tuple[Path, dict[str, Any]]:
    requested = expand_path(path_str)
    if requested.is_absolute():
        resolved = requested.resolve()
        strategy = "absolute"
    else:
        # Keep one deterministic rule for relative delegate paths.
        resolved = (REPO_ROOT / requested).resolve()
        strategy = "repo_root_relative"

    relative_to_repo = repo_relative_path(resolved)
    resolution = {
        "requested": path_str,
        "expanded": str(requested),
        "strategy": strategy,
        "resolved": str(resolved),
        "within_repo_root": relative_to_repo is not None,
        "repo_relative_path": relative_to_repo,
    }
    return resolved, resolution


def resolve_output_path(path_str: str) -> tuple[Path, dict[str, Any]]:
    requested = expand_path(path_str)
    if requested.is_absolute():
        resolved = requested.resolve()
        strategy = "absolute"
    else:
        resolved = (REPO_ROOT / requested).resolve()
        strategy = "repo_root_relative"

    relative_to_repo = repo_relative_path(resolved)
    try:
        relative_to_output_root = str(resolved.relative_to(APPROVED_OUTPUT_ROOT))
        within_output_root = True
    except ValueError:
        relative_to_output_root = None
        within_output_root = False

    resolution = {
        "requested": path_str,
        "expanded": str(requested),
        "strategy": strategy,
        "resolved": str(resolved),
        "within_repo_root": relative_to_repo is not None,
        "repo_relative_path": relative_to_repo,
        "approved_output_root": str(APPROVED_OUTPUT_ROOT),
        "within_approved_output_root": within_output_root,
        "approved_output_relative_path": relative_to_output_root,
    }
    return resolved, resolution


def validate_delegate_script(base_script: Path) -> str | None:
    reviewed_in_repo = repo_relative_path(REVIEWED_BASE_SCRIPT) is not None
    base_in_repo = repo_relative_path(base_script) is not None

    if reviewed_in_repo and not base_in_repo:
        return (
            "Preferred base script must stay within repository root "
            f"{REPO_ROOT} to preserve readonly provenance boundaries."
        )
    if base_script != REVIEWED_BASE_SCRIPT:
        return (
            "Preferred base script must resolve to the reviewed repository script "
            f"{REVIEWED_BASE_SCRIPT} to preserve the readonly preview contract."
        )
    return None


def bool_flag(value: str) -> bool:
    lowered = value.strip().lower()
    if lowered in {"1", "true", "yes", "y", "on"}:
        return True
    if lowered in {"0", "false", "no", "n", "off"}:
        return False
    raise argparse.ArgumentTypeError(f"invalid boolean value: {value}")


def discover_pdfs(input_dir: Path) -> list[str]:
    if not input_dir.exists() or not input_dir.is_dir():
        return []
    return sorted(str(p) for p in input_dir.rglob("*.pdf") if p.is_file())


def parse_delegate_report(stdout_text: str) -> dict[str, Any] | None:
    stripped = stdout_text.strip()
    if not stripped:
        return None

    try:
        payload = json.loads(stripped)
    except json.JSONDecodeError:
        payload = None

    if isinstance(payload, dict):
        return payload

    for line in reversed([line.strip() for line in stripped.splitlines() if line.strip()]):
        try:
            candidate = json.loads(line)
        except json.JSONDecodeError:
            continue
        if isinstance(candidate, dict):
            return candidate
    return None


def load_delegate_report_file(path: Path) -> dict[str, Any] | None:
    if not path.exists() or not path.is_file():
        return None
    try:
        payload = json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return None
    if isinstance(payload, dict):
        return payload
    return None


def build_diagnostic_excerpt(text: str, *, limit: int = DIAGNOSTIC_EXCERPT_LIMIT) -> str:
    cleaned = text.strip()
    if not cleaned:
        return ""
    if len(cleaned) <= limit:
        return cleaned
    return cleaned[:limit] + "...[truncated]"


def line_count(text: str) -> int:
    if not text:
        return 0
    return len(text.splitlines())


def has_strong_delegate_success_evidence(
    delegate_report: dict[str, Any] | None,
    *,
    ocr_mode: str,
) -> tuple[bool, str | None]:
    if not isinstance(delegate_report, dict):
        return False, "Delegate did not emit a structured JSON report for success evidence."

    if str(delegate_report.get("status", "")).strip().lower() != "success":
        return False, "Delegate report did not confirm a success status."

    total_files = delegate_report.get("total_files")
    if not isinstance(total_files, int) or total_files < 1:
        return False, "Delegate report did not confirm at least one processed PDF file."

    status_counter = delegate_report.get("status_counter")
    if isinstance(status_counter, dict):
        failed_count = status_counter.get("failed", 0)
        if isinstance(failed_count, int) and failed_count > 0:
            return False, "Delegate report still records failed file outcomes."
        partial_count = status_counter.get("partial", 0)
        if isinstance(partial_count, int) and partial_count > 0:
            return False, "Delegate report still records partial file outcomes."

    if bool(delegate_report.get("dry_run", False)):
        return False, "Delegate reported dry-run mode, so wrapper success would overclaim execution."

    if delegate_report.get("excel_written") is not True:
        return False, "Delegate report did not attest excel_written=true."

    if delegate_report.get("output_exists") is not True:
        return False, "Delegate report did not attest output_exists=true."

    output_size_bytes = delegate_report.get("output_size_bytes")
    if not isinstance(output_size_bytes, int) or output_size_bytes < 1:
        return False, "Delegate report did not attest a non-empty output_size_bytes value."

    normalized_ocr_mode = str(ocr_mode).strip().lower()
    delegate_ocr_runtime_status = str(delegate_report.get("ocr_runtime_status", "")).strip().lower()
    if normalized_ocr_mode in {"auto", "on"} and delegate_ocr_runtime_status in {"partial", "blocked"}:
        return (
            False,
            (
                "Delegate OCR runtime is not fully available "
                f"(ocr_runtime_status={delegate_ocr_runtime_status}); "
                "wrapper keeps partial status to avoid overclaiming OCR completeness."
            ),
        )

    return True, None


def extract_delegate_error(delegate_report: dict[str, Any] | None) -> str | None:
    if not isinstance(delegate_report, dict):
        return None
    raw_error = delegate_report.get("error")
    if raw_error is None:
        return None
    if isinstance(raw_error, str):
        cleaned = raw_error.strip()
        return cleaned or None
    cleaned = str(raw_error).strip()
    return cleaned or None


def extract_delegate_phase_statuses(delegate_report: dict[str, Any] | None) -> tuple[str, str]:
    if not isinstance(delegate_report, dict):
        return "", ""

    extraction_status = str(delegate_report.get("extraction_status", "")).strip().lower()
    if extraction_status not in ALLOWED_EXTRACTION_STATUSES:
        extraction_status = ""
    export_status = str(delegate_report.get("export_status", "")).strip().lower()
    if export_status not in ALLOWED_EXPORT_STATUSES:
        export_status = ""

    if not extraction_status:
        status = str(delegate_report.get("status", "")).strip().lower()
        if status == "success":
            extraction_status = "success"
        elif status == "partial":
            extraction_status = "partial"
        elif status == "failed":
            extraction_status = "failed"

    if not export_status:
        if bool(delegate_report.get("dry_run", False)):
            export_status = "skipped_dry_run"
        elif delegate_report.get("excel_written") is True:
            export_status = "succeeded"
        elif str(delegate_report.get("status", "")).strip().lower() == "failed":
            export_status = "failed"

    return extraction_status, export_status


def build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(
        description="Best-effort inbox runner that reuses the repository PDF-to-Excel OCR script."
    )
    parser.add_argument("--input-dir", default=DEFAULT_INPUT_DIR)
    parser.add_argument("--output-xlsx", default=DEFAULT_OUTPUT_XLSX)
    parser.add_argument("--ocr", default=DEFAULT_OCR)
    parser.add_argument("--dry-run", type=bool_flag, default=DEFAULT_DRY_RUN)
    parser.add_argument("--origin-id", default=DEFAULT_ORIGIN_ID)
    parser.add_argument("--title", default=DEFAULT_TITLE)
    parser.add_argument("--description", default=DEFAULT_DESCRIPTION)
    parser.add_argument("--labels", nargs="*", default=DEFAULT_LABELS)
    parser.add_argument("--preferred-base-script", default=DEFAULT_PREFERRED_BASE_SCRIPT)
    parser.add_argument("--reference-docs", nargs="*", default=DEFAULT_REFERENCE_DOCS)
    parser.add_argument("--delegate-timeout-seconds", type=int, default=DEFAULT_DELEGATE_TIMEOUT_SECONDS)
    parser.add_argument("--summary-json", default="")
    return parser


def emit_summary(summary: dict[str, Any], summary_json: str) -> None:
    rendered = json.dumps(summary, ensure_ascii=False, indent=2)
    print(rendered)
    if summary_json:
        out_path = expand_path(summary_json)
        out_path.parent.mkdir(parents=True, exist_ok=True)
        out_path.write_text(rendered + "\n", encoding="utf-8")


def main() -> int:
    args = build_parser().parse_args()

    requested_at = utc_now()
    run_id = "bl050-wrapper-" + requested_at.replace(":", "").replace("-", "").replace(".", "")
    input_dir = expand_path(args.input_dir)
    output_xlsx, output_resolution = resolve_output_path(args.output_xlsx)
    base_script, delegate_resolution = resolve_delegate_script(args.preferred_base_script)
    pdfs = discover_pdfs(input_dir)
    readonly_labels_present = any(str(label).strip().lower() == "readonly" for label in args.labels)
    delegate_contract_error = validate_delegate_script(base_script)

    summary: dict[str, Any] = {
        "status": "failed",
        "runner": "artifacts/scripts/pdf_to_excel_ocr_inbox_runner.py",
        "requested_at": requested_at,
        "run_id": run_id,
        "origin": {
            "origin_id": args.origin_id,
            "title": args.title,
            "description": args.description,
            "labels": args.labels,
        },
        "parameters": {
            "input_dir": str(input_dir),
            "output_xlsx": str(output_xlsx),
            "ocr": args.ocr,
            "dry_run": args.dry_run,
            "preferred_base_script": str(base_script),
            "preferred_base_script_requested": args.preferred_base_script,
            "reference_docs": args.reference_docs,
        },
        "contract": {
            "repo_root": str(REPO_ROOT),
            "reviewed_base_script": str(REVIEWED_BASE_SCRIPT),
            "readonly_labels_present": readonly_labels_present,
            "readonly_delegate_verified": delegate_contract_error is None,
            "approved_output_root": str(APPROVED_OUTPUT_ROOT),
            "output_boundary_enforced": True,
            "delegate_timeout_seconds": max(int(args.delegate_timeout_seconds), 1),
            "delegate_success_evidence_policy": (
                "Require delegate report status=success, total_files>=1, no failed files, "
                "and a real XLSX artifact before the wrapper reports success."
            ),
        },
        "provenance": {
            "runner_path": str(RUNNER_PATH),
            "repo_root": str(REPO_ROOT),
            "origin_id": args.origin_id,
            "delegate_path_resolution": delegate_resolution,
            "output_path_resolution": output_resolution,
            "input_dir_resolution": {
                "requested": args.input_dir,
                "resolved": str(input_dir.resolve()),
                "discovery_mode": "recursive_rglob_*.pdf",
            },
        },
        "readonly_attestation": {
            "mode": "local_filesystem_delegate_only",
            "readonly_scope": "no_external_writeback",
            "network_calls_performed": False,
            "trello_write_performed": False,
            "local_filesystem_writes_allowed": not args.dry_run,
            "readonly_label_present": readonly_labels_present,
            "delegate_restricted_to_reviewed_script": delegate_contract_error is None,
            "statement": (
                "Readonly semantics in this wrapper mean no external/Trello writeback. "
                "When dry_run=false, local filesystem artifacts may still be written."
            ),
        },
        "discovery": {
            "input_dir_exists": input_dir.exists(),
            "pdf_count": len(pdfs),
            "pdf_samples": pdfs[:10],
        },
        "execution": {
            "delegated": False,
            "command": [],
            "returncode": None,
            "timeout_seconds": max(int(args.delegate_timeout_seconds), 1),
            "stdout": "",
            "stderr": "",
            "stdout_present": False,
            "stderr_present": False,
            "stdout_line_count": 0,
            "stderr_line_count": 0,
            "stdout_excerpt": "",
            "stderr_excerpt": "",
            "delegate_report": None,
            "delegate_report_source": "none",
            "delegate_report_sidecar_path": "",
            "delegate_extraction_status": "",
            "delegate_export_status": "",
        },
        "output": {
            "exists": False,
            "path": str(output_xlsx),
            "size_bytes": None,
        },
        "notes": [
            "Best-effort wrapper prefers repository reuse over re-implementation.",
            "If XLSX output cannot be produced honestly, the runner reports failure instead of writing mismatched content.",
        ],
    }

    if not readonly_labels_present:
        summary["notes"].append("Readonly label is missing; preserving conservative local-only execution contract.")
    summary["notes"].append(
        "Readonly semantics here mean no external writeback; local filesystem outputs may be written when dry_run=false."
    )

    if output_xlsx.suffix.lower() != ".xlsx":
        summary["notes"].append("Requested output path does not end with .xlsx; refusing mismatched workbook contract.")
        emit_summary(summary, args.summary_json)
        return 2

    if not bool(output_resolution.get("within_approved_output_root", False)):
        summary["notes"].append(
            (
                "Requested output path is outside approved output root "
                f"{APPROVED_OUTPUT_ROOT}; refusing broader local write destination "
                "for governed readonly flow."
            )
        )
        emit_summary(summary, args.summary_json)
        return 6

    if delegate_contract_error:
        summary["notes"].append(delegate_contract_error)
        emit_summary(summary, args.summary_json)
        return 5

    if not pdfs:
        summary["status"] = "partial"
        summary["notes"].append("No PDF files were discovered; skipping delegate execution with a reviewable partial outcome.")
        emit_summary(summary, args.summary_json)
        return 0

    if not base_script.exists():
        summary["notes"].append("Preferred base script was not found; no unsupported fallback conversion was attempted.")
        emit_summary(summary, args.summary_json)
        return 3

    output_xlsx.parent.mkdir(parents=True, exist_ok=True)
    delegate_report_sidecar = Path(
        tempfile.NamedTemporaryFile(
            prefix="argus-delegate-report-",
            suffix=".json",
            delete=False,
        ).name
    )
    delegate_report_sidecar.unlink(missing_ok=True)
    summary["execution"]["delegate_report_sidecar_path"] = str(delegate_report_sidecar)

    cmd = [
        sys.executable,
        str(base_script),
        "--input-dir",
        str(input_dir),
        "--output-xlsx",
        str(output_xlsx),
        "--report-json",
        str(delegate_report_sidecar),
    ]
    if args.ocr:
        cmd.extend(["--ocr", args.ocr])
    if args.dry_run:
        cmd.append("--dry-run")
        summary["notes"].append("Dry run requested; forwarding --dry-run to delegate for end-to-end contract semantics.")

    summary["execution"]["delegated"] = True
    summary["execution"]["command"] = cmd

    try:
        completed = subprocess.run(
            cmd,
            capture_output=True,
            text=True,
            check=False,
            timeout=max(int(args.delegate_timeout_seconds), 1),
        )
    except subprocess.TimeoutExpired as exc:
        summary["execution"]["stderr"] = (
            f"delegate timed out after {max(int(args.delegate_timeout_seconds), 1)} seconds: {exc}"
        )
        output_exists = output_xlsx.exists() and output_xlsx.is_file()
        summary["output"]["exists"] = output_exists
        if output_exists:
            summary["output"]["size_bytes"] = output_xlsx.stat().st_size
        summary["notes"].append(
            f"Delegate timed out after {max(int(args.delegate_timeout_seconds), 1)} seconds."
        )
        emit_summary(summary, args.summary_json)
        delegate_report_sidecar.unlink(missing_ok=True)
        return 124
    except Exception as exc:
        summary["execution"]["stderr"] = f"delegate invocation error: {exc}"
        emit_summary(summary, args.summary_json)
        delegate_report_sidecar.unlink(missing_ok=True)
        return 4

    summary["execution"]["returncode"] = completed.returncode
    summary["execution"]["stdout"] = completed.stdout
    summary["execution"]["stderr"] = completed.stderr
    summary["execution"]["stdout_present"] = bool(completed.stdout.strip())
    summary["execution"]["stderr_present"] = bool(completed.stderr.strip())
    summary["execution"]["stdout_line_count"] = line_count(completed.stdout)
    summary["execution"]["stderr_line_count"] = line_count(completed.stderr)
    summary["execution"]["stdout_excerpt"] = build_diagnostic_excerpt(completed.stdout)
    summary["execution"]["stderr_excerpt"] = build_diagnostic_excerpt(completed.stderr)
    if summary["execution"]["stderr_present"]:
        summary["notes"].append(
            "Delegate stderr was captured and preserved in execution diagnostics."
        )
    if summary["execution"]["stdout_present"] and not parse_delegate_report(completed.stdout):
        summary["notes"].append(
            "Delegate stdout was captured but did not contain a structured JSON report."
        )

    sidecar_report = load_delegate_report_file(delegate_report_sidecar)
    stdout_report = parse_delegate_report(completed.stdout)
    delegate_report = sidecar_report or stdout_report
    summary["execution"]["delegate_report"] = delegate_report
    delegate_extraction_status, delegate_export_status = extract_delegate_phase_statuses(delegate_report)
    summary["execution"]["delegate_extraction_status"] = delegate_extraction_status
    summary["execution"]["delegate_export_status"] = delegate_export_status
    delegate_error = extract_delegate_error(delegate_report)
    if delegate_error:
        summary["notes"].append(f"Delegate reported error: {delegate_error}")
    if delegate_extraction_status or delegate_export_status:
        summary["notes"].append(
            (
                "Delegate phase outcomes: "
                f"extraction_status={delegate_extraction_status or 'unknown'}, "
                f"export_status={delegate_export_status or 'unknown'}."
            )
        )
    if delegate_export_status == "failed" and delegate_extraction_status in {"success", "partial"}:
        summary["notes"].append(
            (
                "Delegate reported export failure after extraction evidence was produced "
                f"(extraction_status={delegate_extraction_status}, export_status=failed)."
            )
        )
    if isinstance(sidecar_report, dict):
        summary["execution"]["delegate_report_source"] = "sidecar"
        if isinstance(stdout_report, dict) and stdout_report != sidecar_report:
            summary["notes"].append("Delegate stdout report diverged from sidecar; using sidecar as canonical evidence.")
    elif isinstance(stdout_report, dict):
        summary["execution"]["delegate_report_source"] = "stdout"
    else:
        summary["execution"]["delegate_report_source"] = "none"

    output_exists = output_xlsx.exists() and output_xlsx.is_file()
    summary["output"]["exists"] = output_exists
    if output_exists:
        summary["output"]["size_bytes"] = output_xlsx.stat().st_size

    delegate_status = ""
    if isinstance(delegate_report, dict):
        candidate = str(delegate_report.get("status", "")).strip().lower()
        if candidate in ALLOWED_SUMMARY_STATUSES:
            delegate_status = candidate

    if args.dry_run:
        if completed.returncode == 0:
            summary["status"] = "partial"
            if isinstance(delegate_report, dict) and bool(delegate_report.get("dry_run", False)):
                summary["notes"].append("Delegate report confirmed dry_run=true.")
            elif isinstance(delegate_report, dict):
                summary["notes"].append("Delegate report did not attest dry_run=true; preserving partial status conservatively.")
            else:
                summary["notes"].append("Delegate did not emit a structured dry-run report; preserving partial status conservatively.")
        else:
            summary["notes"].append(
                "Delegate script returned a non-zero exit code during dry-run mode; hard-failing wrapper outcome."
            )
    elif completed.returncode != 0:
        if delegate_status:
            summary["notes"].append(
                (
                    f"Delegate reported status={delegate_status}, but returncode={completed.returncode}; "
                    "wrapper treats non-zero delegate exits as hard failure."
                )
            )
        else:
            summary["notes"].append("Delegate script returned a non-zero exit code.")
    else:
        if delegate_status == "failed":
            if output_exists:
                summary["notes"].append(
                    "Delegate reported failed status despite producing an XLSX artifact; review extraction/export phase details."
                )
            else:
                summary["notes"].append(
                    "Delegate exited with failed semantics and no XLSX artifact; preserving failed wrapper status."
                )
        elif delegate_status == "partial":
            summary["status"] = "partial"
            if output_exists:
                summary["notes"].append(
                    "Delegate reported a reviewable partial outcome with XLSX artifact; preserving partial status."
                )
            else:
                summary["notes"].append(
                    "Delegate reported a reviewable partial outcome without XLSX artifact; preserving partial status."
                )
        elif output_exists:
            success_evidence_ok, success_evidence_note = has_strong_delegate_success_evidence(
                delegate_report,
                ocr_mode=args.ocr,
            )
            if success_evidence_ok:
                summary["status"] = "success"
            elif delegate_status == "success":
                summary["status"] = "partial"
                summary["notes"].append(
                    success_evidence_note
                    or "Delegate success evidence was too weak for the wrapper to claim success."
                )
            else:
                summary["status"] = "partial"
                summary["notes"].append("Delegate produced XLSX output but did not provide a recognized summary status.")
        else:
            if delegate_status == "success":
                summary["notes"].append(
                    "Delegate reported success but expected XLSX output was not found; preserving failed wrapper status."
                )
            else:
                summary["notes"].append("Delegate exited successfully but expected XLSX output was not found.")

    emit_summary(summary, args.summary_json)
    delegate_report_sidecar.unlink(missing_ok=True)
    return 0 if summary["status"] in {"success", "partial"} else 1


if __name__ == "__main__":
    raise SystemExit(main())
